import{_ as s,o as e,c as n,a2 as i}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"GitHub SSH代理配置","description":"","frontmatter":{},"headers":[],"relativePath":"5 工具/GitHub SSH代理配置.md","filePath":"5 工具/GitHub SSH代理配置.md","lastUpdated":1777009911000}'),t={name:"5 工具/GitHub SSH代理配置.md"};function p(l,a,r,o,c,d){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="github-ssh代理配置" tabindex="-1">GitHub SSH代理配置 <a class="header-anchor" href="#github-ssh代理配置" aria-label="Permalink to &quot;GitHub SSH代理配置&quot;">​</a></h1> <h2 id="问题背景" tabindex="-1">问题背景 <a class="header-anchor" href="#问题背景" aria-label="Permalink to &quot;问题背景&quot;">​</a></h2> <p>Git Clone时，HTTPS协议能自动走系统代理，但SSH协议默认直连，不识别<code>http_proxy</code>环境变量，导致连接GitHub超时。</p> <h2 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h2> <p>通过<code>~/.ssh/config</code>配置<code>ProxyCommand</code>，强制SSH流量经本地代理转发，同时改用443端口绕过22端口封锁。</p> <h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2> <p>编辑 <code>~/.ssh/config</code>：</p> <div class="language-ssh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ssh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host github.com</span></span>
<span class="line"><span> Hostname ssh.github.com</span></span>
<span class="line"><span> Port 443</span></span>
<span class="line"><span> User git</span></span>
<span class="line"><span> # 假设代理端口为7890，根据实际情况修改</span></span>
<span class="line"><span> ProxyCommand nc -X 5 -x 127.0.0.1:7890 %h %p</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h2> <div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -T</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git@github.com</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,18)])])}const u=s(t,[["render",p]]);export{b as __pageData,u as default};
